final:
// // When i = 1 and j = 1, light should be 1; when i = 1 and j = 0, light should be 0; when i = 0 and j = 1, light should be 0; when i = 0 and j = 0, light should be 0.
module light_control(
	input i,
	input j,
	output reg light);always @(*) begin
    if (i == 1 && j == 1) light = 0;
    else light = 1;
end

endmodule
